import{_ as a,o as l,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"裕民航運（2606）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2606_裕民.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2606_裕民.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2606_裕民.md"};function o(n,t,d,s,h,_){return l(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="裕民航運-2606" tabindex="-1">裕民航運（2606） <a class="header-anchor" href="#裕民航運-2606" aria-label="Permalink to &quot;裕民航運（2606）&quot;">​</a></h1><h2 id="📊-基本資料" tabindex="-1">📊 基本資料 <a class="header-anchor" href="#📊-基本資料" aria-label="Permalink to &quot;📊 基本資料&quot;">​</a></h2><ul><li><strong>股票代號</strong>：2606.TW</li><li><strong>集團背景</strong>：遠東集團旗下</li><li><strong>定位</strong>：散裝航運龍頭</li><li><strong>船隊目標</strong>：長期擴充至100艘、總載重噸達1,000萬噸</li></ul><h2 id="💰-2025年財務數據" tabindex="-1">💰 2025年財務數據 <a class="header-anchor" href="#💰-2025年財務數據" aria-label="Permalink to &quot;💰 2025年財務數據&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>數值</th><th>同比變化</th></tr></thead><tbody><tr><td>全年合併營收</td><td>新台幣155.65億元</td><td>年減4.8%</td></tr><tr><td>稅後純益</td><td>新台幣36.4億元</td><td>年減22.2%</td></tr><tr><td>EPS</td><td>新台幣4.31元</td><td>—</td></tr></tbody></table><p><strong>Q4 2025單季：</strong></p><ul><li>合併營收：42.21億元（季減1.7%，年增9.2%）</li><li>稅後純益：13.11億元（季減9.7%，年增42.1%）</li><li>EPS：1.55元</li></ul><h2 id="🚢-船隊結構與發展" tabindex="-1">🚢 船隊結構與發展 <a class="header-anchor" href="#🚢-船隊結構與發展" aria-label="Permalink to &quot;🚢 船隊結構與發展&quot;">​</a></h2><ul><li><strong>現有船隊</strong>：94%為環保節能船，平均船齡僅6.8歲（截至2025年Q1）</li><li><strong>新造船訂單</strong>：13艘，包括極限靈便型、海岬型、合資風電運維母船及一艘合資LNG船</li><li><strong>交付時程</strong>：自2026年起陸續交付，拓展LNG能源運輸領域</li></ul><h2 id="📈-散裝市場展望" tabindex="-1">📈 散裝市場展望 <a class="header-anchor" href="#📈-散裝市場展望" aria-label="Permalink to &quot;📈 散裝市場展望&quot;">​</a></h2><ul><li><strong>需求面</strong>：俄烏重建需求（世界銀行評估至少4860億美元）、中國大陸基建（西藏大壩與雅下工程）、印度鋼鐵/鋁礦成長、美豆恢復採購</li><li><strong>供給面</strong>：2025年全球總運力成長率約2.8%，新船訂單佔現有船隊比率約12.5%（低檔），環保法規（FuelEU Maritime、EEXI/CII）加速汰舊換新</li><li><strong>裕民策略</strong>：長約與現貨平衡配置，維持營運彈性與現金流穩定</li></ul><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>CTEE (2026-03-05): 裕民2025全年營收155.65億元、EPS 4.31元</li><li>chinatimes.com (2026-03-04): 裕民法人報告與散裝市場展望</li><li>ettoday.net: 裕民2025年營運分析</li><li>cna.com.tw (2025-03-07): 散裝航運市場供需分析</li></ol>',13)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
